function extractDriveId(url) {
  if (!url) return null;
  const s = String(url);
  let m = s.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (m) return m[1];
  m = s.match(/\/folders\/([a-zA-Z0-9_-]+)/);
